parameters.text:
={{ (function() {
  const b = $json.body;
  const wa = b.whatsappInboundMessage;
  const evo = b.data;
  if (wa) {
    const phone = (wa.from || '').replace('+','');
    const nameStr = (wa.customerProfile && wa.customerProfile.name) ? wa.customerProfile.name : phone;
    const msg = wa.text && wa.text.body ? wa.text.body : '';
    return "Datos del contacto:\n- Telefono: " + phone + "\n- Nombre WA: " + nameStr + "\n\nMensaje: " + msg;
  } else if (evo) {
    const phone = evo.key && evo.key.remoteJid ? evo.key.remoteJid.split('@')[0] : '';
    const nameStr = evo.pushName || phone;
    const msg = evo.message && evo.message.conversation ? evo.message.conversation : (evo.message && evo.message.extendedTextMessage ? evo.message.extendedTextMessage.text : '');
    return "Datos del contacto:\n- Telefono: " + phone + "\n- Nombre WA: " + nameStr + "\n\nMensaje: " + msg;
  }
  return '';
})() }}

