const output = $input.first().json.output || '';
const match = output.match(/\[CITA:(\{[^\]]+\})\]/);
let cita = {};
if (match) {
  try { cita = JSON.parse(match[1]); } catch(e) {}
}
const cleanText = output.replace(/\[CITA:\{[^\]]+\}\]/, '').trim();
const b = $('WhatsApp LAB').first().json.body;
const wa = b.whatsappInboundMessage;
const evo = b.data;
const remoteJid = wa ? (wa.from || '').replace('+','') : (evo && evo.key ? evo.key.remoteJid.split('@')[0] : '');
return [{ json: { cleanText, cita, remoteJid } }];

